import React from 'react';
import { Link } from 'react-router-dom';

function Navbar() {
  return (
    <nav style={{
      background: '#1a1a2e',
      padding: '15px 30px',
      display: 'flex',
      gap: '30px',
      alignItems: 'center'
    }}>
      <span style={{ color: 'white', fontWeight: 'bold', fontSize: '18px', fontFamily: 'Arial' }}>
        Inventory App
      </span>
      <Link to="/" style={{ color: '#a0a0ff', textDecoration: 'none', fontFamily: 'Arial' }}>
        Dashboard
      </Link>
      <Link to="/products" style={{ color: '#a0a0ff', textDecoration: 'none', fontFamily: 'Arial' }}>
        Products
      </Link>
      <Link to="/sales" style={{ color: '#a0a0ff', textDecoration: 'none', fontFamily: 'Arial' }}>
        Sales
      </Link>
    </nav>
  );
}

export default Navbar;
